+import { NonExhaustiveError } from './errors';
+import * as symbols from './internals/symbols';
+import { matchPattern } from './internals/helpers';
+import type { Pattern } from './types/Pattern';
+import type { MatchEach } from './types/MatchEach';
+
+type Clause = { patterns?: Pattern<any>[]; predicate?: (value: any) => unknown; handler: (selection: unknown, value: any) => unknown };
+type Operation = Clause | { tap: (result: unknown) => void };
+
+/**
+ * Creates a pattern matching expression that evaluates every matching clause.
+ */
+export function matchEach<const input, output = symbols.unset>(value: input): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, output>;
+export function matchEach(value?: unknown): any {
+  return new MatchEachExpression([]).withInput(arguments.length ? value : undefined);
+}
+
+class MatchEachExpression {
+  constructor(private operations: Operation[], private inputSet = false, private input: unknown = undefined) {}
+
+  withInput(input: unknown): MatchEachExpression {
+    return new MatchEachExpression(this.operations, true, input);
+  }
+
+  with(...args: any[]): MatchEachExpression {
+    const handler = args[args.length - 1];
+    const patterns: Pattern<any>[] = [args[0]];
+    let predicate: ((value: any) => unknown) | undefined;
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns.push(...args.slice(1, -1));
+    return new MatchEachExpression([...this.operations, { patterns, predicate, handler }], this.inputSet, this.input);
+  }
+
+  when(predicate: (value: any) => unknown, handler: (value: any) => unknown): MatchEachExpression {
+    return new MatchEachExpression([...this.operations, { predicate, handler }], this.inputSet, this.input);
+  }
+
+  tap(callback: (result: unknown) => void): MatchEachExpression {
+    return new MatchEachExpression([...this.operations, { tap: callback }], this.inputSet, this.input);
+  }
+
+  otherwise(handler: (value: any) => unknown): unknown[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [handler(this.input)];
+  }
+
+  exhaustive(fallback = defaultCatcher): unknown[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [fallback(this.input)];
+  }
+
+  run(): unknown[] { return this.exhaustive(); }
+  returnType() { return this; }
+  narrow() { return this; }
+  toFunction() { return (input: unknown) => this.evaluateOrThrow(input); }
+  toExhaustiveFunction() { return (input: unknown) => this.evaluateOrThrow(input); }
+  toPartialFunction() { return (input: unknown) => { const results = this.evaluate(input); return results.length ? results : undefined; }; }
